using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_WithItems_ContainsAllItems()
    {
        // Arrange
        var items = new List<string> { "A", "B", "C" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.Equal(3, result.Count);
        Assert.Equal("A", result[0]);
        Assert.Equal("B", result[1]);
        Assert.Equal("C", result[2]);
    }

    [Theory]
    [InlineData(10, 3, 4)]   // 10 items / 3 per page = 4 pages (ceil)
    [InlineData(9, 3, 3)]    // 9 items / 3 per page = 3 pages
    [InlineData(1, 10, 1)]   // 1 item / 10 per page = 1 page
    [InlineData(0, 10, 0)]   // 0 items / 10 per page = 0 pages
    [InlineData(15, 5, 3)]   // 15 items / 5 per page = 3 pages
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Theory]
    [InlineData(1, false)]   // First page has no previous
    [InlineData(2, true)]    // Second page has previous
    [InlineData(3, true)]    // Third page has previous
    public void HasPreviousPage_VariousPageIndexes_ReturnsCorrectly(int pageIndex, bool expected)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]   // Page 1 of 3 has next
    [InlineData(2, 3, true)]   // Page 2 of 3 has next
    [InlineData(3, 3, false)]  // Page 3 of 3 has no next
    [InlineData(1, 1, false)]  // Page 1 of 1 has no next
    public void HasNextPage_VariousPageIndexes_ReturnsCorrectly(int pageIndex, int totalPages, bool expected)
    {
        // Arrange - set count so TotalPages equals totalPages with pageSize=10
        int count = totalPages * 10;

        // Act
        var result = new PaginatedList<int>(new List<int>(), count, pageIndex, 10);

        // Assert
        Assert.Equal(expected, result.HasNextPage);
    }

    [Fact]
    public void Constructor_SetsPageIndex()
    {
        // Act
        var result = new PaginatedList<string>(new List<string>(), 10, 3, 5);

        // Assert
        Assert.Equal(3, result.PageIndex);
    }

    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
        Assert.Equal(2, result.PageIndex);
        Assert.True(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
        Assert.True(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<string>().AsQueryable();

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_SingleItemSinglePage_NoNavigation()
    {
        // Arrange
        var source = new[] { "only" }.AsQueryable();

        // Act
        var result = PaginatedList<string>.Create(source, 1, 10);

        // Assert
        Assert.Single(result);
        Assert.Equal("only", result[0]);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain queue to avoid cross-test pollution
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_CreateOperation_EnqueuesWithCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_UpdateOperation_EnqueuesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        Assert.Equal("UPDATE", notification.Operation);
        Assert.Equal("Teacher", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_DeleteOperation_EnqueuesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        Assert.Equal("DELETE", notification.Operation);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Instructor", "99", null, EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Instructor (ID: 99) has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SimpleOverload_EnqueuesCorrectly()
    {
        // Act  
        _sut.SendNotification("Student", "10", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student (ID: 10) has been updated", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleEnqueued_ReturnsFifoOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("A", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.Equal("B", second!.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.Equal("C", third!.EntityType);

        Assert.Null(_sut.ReceiveNotification());
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [Fact]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "5", "  ", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student (ID: 5) has been updated", notification.Message);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op implementation should not throw)
        var exception = Record.Exception(() => _sut.MarkAsRead(42));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var svc = new NotificationService();
        var exception = Record.Exception(() => svc.Dispose());
        Assert.Null(exception);
    }
}

