namespace ContosoUniversity.Tests;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        // Drain static queue to prevent cross-test interference
        var svc = new ContosoUniversity.Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.NotNull(result);
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsEmptyList()
    {
        // Drain any existing notifications
        var svc = new ContosoUniversity.Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        var value = result.Value;
        Assert.NotNull(value);
        // Verify it's a success response with notifications
        var json = Newtonsoft.Json.JsonConvert.SerializeObject(value);
        Assert.Contains("\"success\":true", json);
        Assert.Contains("\"count\":0", json);
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.NotNull(result);
        var value = result.Value;
        Assert.NotNull(value);
        var json = Newtonsoft.Json.JsonConvert.SerializeObject(value);
        Assert.Contains("\"success\":true", json);
    }
}

