            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID, Enrollments = new List<Enrollment>() };
