+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+
+namespace ContosoUniversity.Tests;
+
+public class NotificationServiceTests : IDisposable
+{
+    private readonly NotificationService _sut;
+
+    public NotificationServiceTests()
+    {
+        _sut = new NotificationService();
+        // Drain any leftover notifications from other tests (static queue)
+        while (_sut.ReceiveNotification() != null) { }
+    }
+
+    public void Dispose()
+    {
+        // Drain queue to avoid cross-test pollution
+        while (_sut.ReceiveNotification() != null) { }
+        _sut.Dispose();
+    }
+
+    [Fact]
+    public void SendNotification_CreateOperation_EnqueuesWithCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Student", notification.EntityType);
+        Assert.Equal("1", notification.EntityId);
+        Assert.Equal("CREATE", notification.Operation);
+        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
+        Assert.Equal("Admin", notification.CreatedBy);
+        Assert.False(notification.IsRead);
+    }
+
+    [Fact]
+    public void SendNotification_UpdateOperation_EnqueuesCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Course", "42", "Chemistry", EntityOperation.UPDATE, "Teacher");
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
+        Assert.Equal("UPDATE", notification.Operation);
+        Assert.Equal("Teacher", notification.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_DeleteOperation_EnqueuesCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
+        Assert.Equal("DELETE", notification.Operation);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _sut.SendNotification("Instructor", "99", null, EntityOperation.CREATE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("New Instructor (ID: 99) has been created", notification.Message);
+    }
+
+    [Fact]
+    public void SendNotification_WithoutUserName_DefaultsToSystem()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("System", notification.CreatedBy);
+    }
+
+    [Fact]
+    public void SendNotification_SimpleOverload_EnqueuesCorrectly()
+    {
+        // Act  
+        _sut.SendNotification("Student", "10", EntityOperation.UPDATE, "Admin");
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Student (ID: 10) has been updated", notification.Message);
+        Assert.Equal("Admin", notification.CreatedBy);
+    }
+
+    [Fact]
+    public void ReceiveNotification_EmptyQueue_ReturnsNull()
+    {
+        // Act
+        var result = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.Null(result);
+    }
+
+    [Fact]
+    public void ReceiveNotification_MultipleEnqueued_ReturnsFifoOrder()
+    {
+        // Arrange
+        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
+        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
+        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);
+
+        // Act & Assert
+        var first = _sut.ReceiveNotification();
+        Assert.Equal("A", first!.EntityType);
+
+        var second = _sut.ReceiveNotification();
+        Assert.Equal("B", second!.EntityType);
+
+        var third = _sut.ReceiveNotification();
+        Assert.Equal("C", third!.EntityType);
+
+        Assert.Null(_sut.ReceiveNotification());
+    }
+
+    [Fact]
+    public void SendNotification_SetsCreatedAtToRecentTime()
+    {
+        // Arrange
+        var before = DateTime.Now.AddSeconds(-1);
+
+        // Act
+        _sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.True(notification.CreatedAt >= before);
+        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
+    }
+
+    [Fact]
+    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _sut.SendNotification("Student", "5", "  ", EntityOperation.UPDATE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Student (ID: 5) has been updated", notification.Message);
+    }
+
+    [Fact]
+    public void MarkAsRead_DoesNotThrow()
+    {
+        // Act & Assert (no-op implementation should not throw)
+        var exception = Record.Exception(() => _sut.MarkAsRead(42));
+        Assert.Null(exception);
+    }
+
+    [Fact]
+    public void Dispose_DoesNotThrow()
+    {
+        // Act & Assert
+        var svc = new NotificationService();
+        var exception = Record.Exception(() => svc.Dispose());
+        Assert.Null(exception);
+    }
+}
+

