+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(8, _context.Students.Count());
+        Assert.Contains(_context.Students, s => s.LastName == "Alexander");
+        Assert.Contains(_context.Students, s => s.LastName == "Alonso");
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsInstructors()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(5, _context.Instructors.Count());
+        Assert.Contains(_context.Instructors, i => i.LastName == "Abercrombie");
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsDepartments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(4, _context.Departments.Count());
+        Assert.Contains(_context.Departments, d => d.Name == "English");
+        Assert.Contains(_context.Departments, d => d.Name == "Mathematics");
+        Assert.Contains(_context.Departments, d => d.Name == "Engineering");
+        Assert.Contains(_context.Departments, d => d.Name == "Economics");
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsCourses()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(7, _context.Courses.Count());
+        Assert.Contains(_context.Courses, c => c.Title == "Chemistry");
+        Assert.Contains(_context.Courses, c => c.Title == "Calculus");
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsEnrollments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(11, _context.Enrollments.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(3, _context.OfficeAssignments.Count());
+    }
+
+    [Fact]
+    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
+    {
+        // Act
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(8, _context.CourseAssignments.Count());
+    }
+
+    [Fact]
+    public void Initialize_AlreadySeeded_DoesNotDuplicate()
+    {
+        // Arrange - seed once
+        DbInitializer.Initialize(_context);
+        int studentCount = _context.Students.Count();
+
+        // Act - seed again
+        DbInitializer.Initialize(_context);
+
+        // Assert
+        Assert.Equal(studentCount, _context.Students.Count());
